import { computed, ref } from 'vue'

export type AppLocale = 'zh-CN' | 'en-US'

export function detectSystemLocale(): AppLocale {
  const languages = typeof navigator === 'undefined'
    ? []
    : (Array.isArray(navigator.languages) && navigator.languages.length ? navigator.languages : [navigator.language])
  return languages.some((language) => String(language || '').toLowerCase().startsWith('zh')) ? 'zh-CN' : 'en-US'
}

const locale = ref<AppLocale>(detectSystemLocale())

