export function setLocale(value: AppLocale) {
  locale.value = value
  if (typeof document !== 'undefined') document.documentElement.lang = value
}

export function useLocale() {
  return computed(() => locale.value)
}

export function t(key: keyof typeof messages['zh-CN'], params?: Record<string, string | number>): string {
  const value: string = messages[locale.value][key] || messages['zh-CN'][key] || key
  if (!params) return value
  return Object.entries(params).reduce((text, [name, replacement]) => text.replaceAll(`{${name}}`, String(replacement)), value)
}
